# ===== MT5 鍏ㄦ祦绋嬭嚜鍔ㄥ寲閮ㄧ讲 (鍚瘝鏈畨瑁? ===== # 閫傜敤浜庨樋閲屼簯棣欐腐鏈嶅姟鍣?- 鐩磋繛 GitHub  # [閰嶇疆鍖篯 $githubBase = "https://raw.githubusercontent.com/F96371/MT5_Deploy/main" $eaUrl = "$githubBase/鏅烘眹鐭╅樀 V102 鐗堟湰 (ssai).ex5" $eaName = "鏅烘眹鐭╅樀 V102 鐗堟湰 (ssai).ex5"  # 1. 涓嬭浇骞堕潤榛樺畨瑁呮瘝鏈?Write-Host "`n[1/4] 姝ｅ湪涓嬭浇骞堕潤榛樺畨瑁?MT5 姣嶆湰..." -ForegroundColor Cyan $setupPath = "$env:TEMP\exness5setup.exe" Invoke-WebRequest -Uri "$githubBase/exness5setup.exe" -OutFile $setupPath Start-Process -FilePath $setupPath -ArgumentList "/path:C:\MT5_Master /auto" -Wait Stop-Process -Name "terminal64" -Force -ErrorAction SilentlyContinue  # 2. 鎵归噺鍏嬮殕涓庣幆澧冮殧绂?Write-Host "[2/4] 姝ｅ湪鍏嬮殕 5 涓嫭绔嬩氦鏄撶幆澧?.." -ForegroundColor Cyan 1..5 | ForEach-Object {     $n = "{0:D2}" -f $_     $target = "C:\MT5_$n"     if (!(Test-Path $target)) { Copy-Item "C:\MT5_Master" $target -Recurse -Force } }  # 3. 浠庝簯绔帹閫?EA 绛栫暐 Write-Host "[3/4] 姝ｅ湪浠庝簯绔帹閫?EA 绛栫暐..." -ForegroundColor Cyan 1..5 | ForEach-Object {     $n = "{0:D2}" -f $_     $dir = "C:\MT5_$n\MQL5\Experts\"     if (!(Test-Path $dir)) { New-Item $dir -Type Directory -Force }     Invoke-WebRequest -Uri $eaUrl -OutFile "$dir\$eaName" }  # 4. 鐢熸垚妗岄潰蹇嵎鏂瑰紡骞舵敞鍏ュ紑鏈鸿嚜鍚?Write-Host "[4/4] 姝ｅ湪閰嶇疆鑷惎鍔ㄥ揩鎹锋柟寮?.." -ForegroundColor Cyan $Wsh = New-Object -ComObject WScript.Shell 1..5 | ForEach-Object {     $n = "{0:D2}" -f $_     $lnk = "$([Environment]::GetFolderPath('Desktop'))\Account_$n.lnk"     $sc = $Wsh.CreateShortcut($lnk)     $sc.TargetPath = "C:\MT5_$n\terminal64.exe"     $sc.Arguments = "/portable /skipupdate"     $sc.WorkingDirectory = "C:\MT5_$n"     $sc.Save()     Copy-Item $lnk "$([Environment]::GetFolderPath('Startup'))\" -Force }  Write-Host "`n 鎵€鏈夋祦绋嬪凡瀹屾垚锛? -ForegroundColor Green Write-Host "璇锋墜鍔ㄧ櫥褰?5 涓处鎴峰苟璁剧疆锛? -ForegroundColor Yellow Write-Host "  1. Ctrl+O -> Charts -> Max bars = 5000" -ForegroundColor Yellow Write-Host "  2. Ctrl+O -> Expert Advisors -> 鍕鹃€変袱椤? -ForegroundColor Yellow